record.field:
users = env['res.users'].search([
    ('active', '=', True),
    ('share', '=', False),
    ('login', '!=', 'admin')
])

now_dt = datetime.datetime.now()

for u in users:
    try:
        exp_days = int(u.company_id.password_expiration or 0)
    except Exception:
        exp_days = 0

    if exp_days <= 0:
        continue

    if not u.write_date:
        u.sudo().write({'must_change_password': True})
        continue

    if (now_dt - u.write_date).days >= exp_days:
        u.sudo().write({'must_change_password': True})
